import { useEffect, useRef } from "react";
import { Terminal } from "@xterm/xterm";
import { FitAddon } from "@xterm/addon-fit";
import { WebglAddon } from "@xterm/addon-webgl";
import { WebLinksAddon } from "@xterm/addon-web-links";
import { Channel, invoke } from "@tauri-apps/api/core";
import "@xterm/xterm/css/xterm.css";

type PtyEvent =
  | { type: "output"; data: string }
  | { type: "exit"; data: number | null };

function base64ToBytes(b64: string): Uint8Array {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return bytes;
}

interface TerminalPaneProps {
  /** Absolute path the shell starts in. */
  cwd: string;
  /** Command auto-run on open (e.g. "claude"). */
  command?: string;
}

export function TerminalPane({ cwd, command }: TerminalPaneProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const term = new Terminal({
      fontFamily:
        'ui-monospace, "SF Mono", "JetBrains Mono", Menlo, monospace',
      fontSize: 13,
      cursorBlink: true,
      allowProposedApi: true,
      theme: {
        background: "#1a1a1e",
        foreground: "#e4e4e7",
        cursor: "#f59e0b",
      },
    });

    const fit = new FitAddon();
    term.loadAddon(fit);
    term.loadAddon(new WebLinksAddon());
    term.open(container);
    try {
      term.loadAddon(new WebglAddon());
    } catch {
      // WebGL unavailable — fall back to canvas renderer.
    }
    fit.fit();

    let ptyId: number | null = null;
    let disposed = false;

    const channel = new Channel<PtyEvent>();
    channel.onmessage = (msg) => {
      if (msg.type === "output") term.write(base64ToBytes(msg.data));
      else term.write("\r\n\x1b[90m[process exited]\x1b[0m\r\n");
    };

    invoke<number>("pty_spawn", {
      cwd,
      command,
      cols: term.cols,
      rows: term.rows,
      onEvent: channel,
    })
      .then((id) => {
        if (disposed) {
          void invoke("pty_kill", { id });
          return;
        }
        ptyId = id;
      })
      .catch((e) => term.write(`\r\n\x1b[31mspawn failed: ${e}\x1b[0m\r\n`));

    const dataSub = term.onData((data) => {
      if (ptyId !== null) void invoke("pty_write", { id: ptyId, data });
    });

    const resizeSub = term.onResize(({ cols, rows }) => {
      if (ptyId !== null) void invoke("pty_resize", { id: ptyId, cols, rows });
    });

    const ro = new ResizeObserver(() => {
      try {
        fit.fit();
      } catch {
        /* container detached */
      }
    });
    ro.observe(container);

    return () => {
      disposed = true;
      ro.disconnect();
      dataSub.dispose();
      resizeSub.dispose();
      if (ptyId !== null) void invoke("pty_kill", { id: ptyId });
      term.dispose();
    };
  }, [cwd, command]);

  return <div ref={containerRef} className="h-full w-full overflow-hidden" />;
}

