import { useState } from "react";
import { open } from "@tauri-apps/plugin-dialog";
import { FolderOpen, Play, Settings, Flame } from "lucide-react";
import { Button } from "@/components/ui/button";
import { TerminalPane } from "@/components/TerminalPane";

function basename(p: string): string {
  return p.split("/").filter(Boolean).pop() ?? p;
}

function App() {
  const [projectPath, setProjectPath] = useState<string | null>(null);

  async function openProject() {
    const selected = await open({ directory: true, multiple: false });
    if (typeof selected === "string") setProjectPath(selected);
  }

  return (
    <div className="flex h-full flex-col bg-background text-foreground">
      {/* Top bar */}
      <header className="flex h-11 shrink-0 items-center justify-between border-b px-3">
        <div className="flex items-center gap-2">
          <Flame className="size-4 text-primary" />
          <span className="text-sm font-semibold tracking-tight">Emberyx</span>
          {projectPath && (
            <>
              <span className="text-muted-foreground">/</span>
              <button
                onClick={openProject}
                className="rounded px-1.5 py-0.5 text-sm text-muted-foreground hover:bg-accent hover:text-foreground"
                title={projectPath}
              >
                {basename(projectPath)}
              </button>
            </>
          )}
        </div>

        <div className="flex items-center gap-1.5">
          <Button variant="secondary" size="sm" disabled title="Coming in M2">
            <Play className="size-3.5" />
            Dev
          </Button>
          <Button variant="ghost" size="icon" title="Settings">
            <Settings className="size-4" />
          </Button>
        </div>
      </header>

      {/* Main */}
      <main className="min-h-0 flex-1 bg-[#1a1a1e] p-1">
        {projectPath ? (
          <TerminalPane
            key={projectPath}
            cwd={projectPath}
            command="claude"
          />
        ) : (
          <div className="flex h-full flex-col items-center justify-center gap-4 text-center">
            <Flame className="size-10 text-primary/60" />
            <div>
              <h1 className="text-lg font-semibold">Open a project</h1>
              <p className="text-sm text-muted-foreground">
                Emberyx launches your agent in an integrated terminal.
              </p>
            </div>
            <Button onClick={openProject}>
              <FolderOpen className="size-4" />
              Open project…
            </Button>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;

